module gray_counter_core #(
    parameter integer WIDTH = 4
) (
    input  logic             clk,
    input  logic             rst_n,
    input  logic             enable,
    input  logic             clear,
    output logic [WIDTH-1:0] gray_value,
    output logic [WIDTH-1:0] bin_value,
    output logic             done
);

    localparam [WIDTH-1:0] MAX_BIN = {WIDTH{1'b1}};

    // Explicit FSM states from SSOT fsm.control.
    localparam [2:0] IDLE       = 3'd0,
                     RUN        = 3'd1,
                     WRAP_PULSE = 3'd2,
                     CLEARED    = 3'd3,
                     RESET      = 3'd4;

    // WIDTH legality marker participates in live logic to avoid unused-signal lint.
    logic width_ok;
    assign width_ok = (WIDTH >= 2);

    // Architectural state: registered Gray output and one-cycle done pulse.
    logic [WIDTH-1:0] gray_state;
    logic             done_state;

    // FSM state registers.
    logic [2:0] state;
    logic [2:0] next_state;

    // Decode current Gray to binary combinationally (no loops/functions).
    // Prefix-XOR expansion using log-depth shift/XOR chain.
    logic [WIDTH-1:0] gray_to_bin_s1;
    logic [WIDTH-1:0] gray_to_bin_s2;
    logic [WIDTH-1:0] gray_to_bin_s3;
    logic [WIDTH-1:0] gray_to_bin_s4;
    logic [WIDTH-1:0] gray_to_bin_s5;
    logic [WIDTH-1:0] curr_bin;

    assign gray_to_bin_s1 = gray_state ^ (gray_state >> 1);
    assign gray_to_bin_s2 = gray_to_bin_s1 ^ (gray_to_bin_s1 >> 2);
    assign gray_to_bin_s3 = gray_to_bin_s2 ^ (gray_to_bin_s2 >> 4);
    assign gray_to_bin_s4 = gray_to_bin_s3 ^ (gray_to_bin_s3 >> 8);
    assign gray_to_bin_s5 = gray_to_bin_s4 ^ (gray_to_bin_s4 >> 16);
    assign curr_bin       = gray_to_bin_s5;

    // Advance path from current sampled state.
    logic [WIDTH-1:0] next_bin;
    logic [WIDTH-1:0] next_gray;
    logic             wrap_detect;

    assign next_bin    = curr_bin + {{(WIDTH-1){1'b0}}, 1'b1};
    assign next_gray   = next_bin ^ (next_bin >> 1);
    assign wrap_detect = (curr_bin == MAX_BIN);

    // Observable outputs: gray/done are registered; bin is combinational decode of gray.
    assign gray_value = gray_state;
    assign done       = done_state;
    assign bin_value  = curr_bin;

    // FSM next-state decode for SSOT transitions.
    // reset dominates all controls; clear has priority over enable when rst_n is high.
    always @(*) begin
        next_state = state;

        if (!rst_n) begin
            next_state = RESET;
        end else if (!width_ok) begin
            next_state = RESET;
        end else begin
            case (state)
                RESET: begin
                    // transition_0: RESET -> IDLE after rst_n deassertion and first edge.
                    next_state = IDLE;
                end

                IDLE: begin
                    // transition_1: IDLE -> CLEARED on sampled clear.
                    // transition_2: IDLE -> RUN on sampled enable when clear is low.
                    if (clear) begin
                        next_state = CLEARED;
                    end else if (enable) begin
                        next_state = RUN;
                    end else begin
                        next_state = IDLE;
                    end
                end

                RUN: begin
                    if (clear) begin
                        next_state = CLEARED;
                    end else if (enable && wrap_detect) begin
                        // transition_3: RUN -> WRAP_PULSE on max->0 wrap.
                        next_state = WRAP_PULSE;
                    end else if (!enable) begin
                        // transition_4: RUN -> IDLE when enable sampled low.
                        next_state = IDLE;
                    end else begin
                        next_state = RUN;
                    end
                end

                WRAP_PULSE: begin
                    if (clear) begin
                        next_state = CLEARED;
                    end else if (enable) begin
                        // transition_5: WRAP_PULSE -> RUN when enable remains high.
                        next_state = RUN;
                    end else begin
                        // transition_6: WRAP_PULSE -> IDLE when enable is low after pulse.
                        next_state = IDLE;
                    end
                end

                CLEARED: begin
                    if (clear) begin
                        next_state = CLEARED;
                    end else begin
                        // transition_7: CLEARED -> IDLE when clear low on next edge.
                        next_state = IDLE;
                    end
                end

                default: begin
                    next_state = RESET;
                end
            endcase
        end
    end

    // Commit ordering reset > clear > enable > hold.
    // latency=1 rule: accepted enable updates gray/done in this same edge commit.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            gray_state <= {WIDTH{1'b0}};
            done_state <= 1'b0;
            state      <= RESET;
        end else if (!width_ok) begin
            // Deterministic safe state if illegal parameterization is forced.
            gray_state <= {WIDTH{1'b0}};
            done_state <= 1'b0;
            state      <= RESET;
        end else begin
            state <= next_state;

            if (clear) begin
                gray_state <= {WIDTH{1'b0}};
                done_state <= 1'b0;
            end else if (enable) begin
                gray_state <= next_gray;
                done_state <= wrap_detect;
            end else begin
                gray_state <= gray_state;
                done_state <= 1'b0;
            end
        end
    end

endmodule

